#include <stdio.h>
#include <limits.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int prices[N][M], discounts[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d %d", &prices[i][j], &discounts[i][j]);
            }
        }
        int dp[N][M];
        for (int i = 0; i < M; i++) {
            dp[0][i] = prices[0][i];
        }
        for (int i = 1; i < N; i++) {
            for (int j = 0; j < M; j++) {
                int min = INT_MAX;
                for (int k = 0; k < M; k++) {
                    int cost = dp[i - 1][k] + (k == j ? (prices[i][j] - discounts[i - 1][k]) > 0 ? (prices[i][j] - discounts[i - 1][k]) : 0 : prices[i][j]);
                    if (cost < min) {
                        min = cost;
                    }
                }
                dp[i][j] = min;
            }
        }
        int min = INT_MAX;
        for (int i = 0; i < M; i++) {
            if (dp[N - 1][i] < min) {
                min = dp[N - 1][i];
            }
        }
        printf("%d\n", min);
    }
    return 0;
}

