                    discounts[i][j] = sc.nextInt();
                }
            }
            int[][] dp = new int[N][M];
            for (int i = 0; i < M; i++) {
                dp[0][i] = prices[0][i];
            }
            for (int i = 1; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    int min = Integer.MAX_VALUE;
                    for (int k = 0; k < M; k++) {
                        int cost = dp[i - 1][k] + (k == j ? (prices[i][j] - discounts[i - 1][k]) > 0 ? (prices[i][j] - discounts[i - 1][k]) : 0 : prices[i][j]);
                        if (cost < min) {
                            min = cost;
                        }
                    }
                    dp[i][j] = min;
                }
            }
