for _ in range(T):
    N, M = map(int, input().split())
    prices = [[0 for _ in range(M)] for _ in range(N)]
    discounts = [[0 for _ in range(M)] for _ in range(N)]
    for i in range(N):
        for j in range(M):
            prices[i][j], discounts[i][j] = map(int, input().split())
    dp = [[0 for _ in range(M)] for _ in range(N)]
    for i in range(M):
        dp[0][i] = prices[0][i]
    for i in range(1, N):
        for j in range(M):
            min_val = float('inf')
            for k in range(M):
                cost = dp[i - 1][k] + (prices[i][j] - discounts[i - 1][k] if k == j and prices[i][j] - discounts[i - 1][k] > 0 else prices[i][j])
                if cost < min_val:
                    min_val = cost
            dp[i][j] = min_val
    min_val = float('inf')
    for i in range(M):
        if dp[N - 1][i] < min_val:
            min_val = dp[N - 1][i]
    print(min_val)

