    const prices = Array(N).fill(0).map(() => Array(M).fill(0));
    const discounts = Array(N).fill(0).map(() => Array(M).fill(0));
    for (let j = 0; j < N; j++) {
        const line = readline().split(' ').map(Number);
        for (let k = 0; k < M; k++) {
            prices[j][k] = line[k * 2];
            discounts[j][k] = line[k * 2 + 1];
        }
    }
    const dp = Array(N).fill(0).map(() => Array(M).fill(0));
    for (let j = 0; j < M; j++) {
        dp[0][j] = prices[0][j];
    }
    for (let j = 1; j < N; j++) {
        for (let k = 0; k < M; k++) {
            let min = Infinity;
            for (let l = 0; l < M; l++) {
                const cost = dp[j - 1][l] + (k === l ? (prices[j][k] - discounts[j - 1][l]) > 0 ? (prices[j][k] - discounts[j - 1][l]) : 0 : prices[j][k]);
                if (cost < min) {
                    min = cost;
                }
            }
            dp[j][k] = min;
        }
    }
    let min = Infinity;
